  })

  it('returns false when countryCode does not match', () => {
    const geoData = { countryCode: 'JP', country: 'Japan' }
    expect(isInRegion(geoData, ['US', 'CA', 'GB'])).toBe(false)
  })

  it('performs case-insensitive comparison', () => {
    const geoData = { countryCode: 'us' }
    expect(isInRegion(geoData, ['US'])).toBe(true)

    const geoData2 = { countryCode: 'US' }
    expect(isInRegion(geoData2, ['us'])).toBe(true)
  })

  it('returns false when countryCode is undefined', () => {
    const geoData = {}
    expect(isInRegion(geoData, ['US', 'CA'])).toBe(false)
  })
})

